/**
 * Priority Queue implementation (Min Heap)
 * Stores elements as [distance, node]
 */
class PriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    enqueue(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }

    bubbleUp(index) {
        while (index > 0) {
            let parentIndex = Math.floor((index - 1) / 2);
            // Compare distances (element[0])
            if (this.heap[index][0] < this.heap[parentIndex][0]) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    bubbleDown(index) {
        const lastIndex = this.heap.length - 1;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let smallest = index;

            // Compare distances
            if (leftChildIndex <= lastIndex && this.heap[leftChildIndex][0] < this.heap[smallest][0]) {
                smallest = leftChildIndex;
            }

            if (rightChildIndex <= lastIndex && this.heap[rightChildIndex][0] < this.heap[smallest][0]) {
                smallest = rightChildIndex;
            }

            if (smallest !== index) {
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            } else {
                break;
            }
        }
    }
}


function solve(n, prices, roads) {
    // Adjacency list structure: adj[u] = [{v: neighbor, cost: C, tax: T}, ...]
    const adj = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        // Roads are bidirectional
        adj[u].push({ v: v, cost: cost, tax: tax });
        adj[v].push({ v: u, cost: cost, tax: tax });
    }

    const INF = 1e18; // Use a sufficiently large number for infinity

    /**
     * Runs Dijkstra's algorithm from a single source node.
     * @param {number} startNode The starting node index.
     * @param {function} weightFn Function to calculate edge weight: (edge) => weight
     * @returns {number[]} Array of shortest distances from startNode to all other nodes.
     */
    const dijkstra = (startNode, weightFn) => {
        const dist = Array(n).fill(INF);
        dist[startNode] = 0;
        const pq = new PriorityQueue();

        // PQ stores [distance, node]
        pq.enqueue([0, startNode]);

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > dist[u]) {
                continue;
            }

            for (const edge of adj[u]) {
                const v = edge.v;
                const weight = weightFn(edge);

                const newDist = dist[u] + weight;

                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.enqueue([newDist, v]);
                }
            }
        }
        return dist;
    };

    // --- Step 1: Calculate D_empty (Shortest paths using only 'cost') ---
    // D_empty[i][j] = shortest path from i to j (empty-handed)
    const D_empty = Array(n).fill(0).map(() => Array(n).fill(INF));

    for (let i = 0; i < n; i++) {
        // Weight function for empty travel: use edge.cost
        const emptyDistances = dijkstra(i, (edge) => edge.cost);
        for (let j = 0; j < n; j++) {
            D_empty[i][j] = emptyDistances[j];
        }
    }

    // --- Step 2: Calculate D_tax (Shortest paths using 'cost * tax') ---
    // D_tax[j][i] = shortest path from j to i (carrying apples)
    // We need this matrix, so we run Dijkstra N times.
    const D_tax = Array(n).fill(0).map(() => Array(n).fill(INF));

    for (let j = 0; j < n; j++) {
        // Weight function for tax travel: use edge.cost * edge.tax
        // Note: Since C <= 10^9 and T <= 100, C*T <= 10^11. JS numbers are fine.
        const taxDistances = dijkstra(j, (edge) => edge.cost * edge.tax);
        for (let i = 0; i < n; i++) {
            D_tax[j][i] = taxDistances[i];
        }
    }

    // --- Step 3: Calculate Final Answer ANS[i] ---
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i
        let minCost = prices[i];

        // Option 2: Go from i to j, buy at j, return j to i
        for (let j = 0; j < n; j++) {
            if (i === j) {
                continue; // This case is covered by Option 1, and path cost would be 0 + prices[i] + 0
            }

            // Cost = D_empty(i, j) + prices[j] + D_tax(j, i)

            const empty_i_j = D_empty[i][j];
            const tax_j_i = D_tax[j][i];

            // Check if paths exist (avoid INF arithmetic issues if we were using BigInt, but here INF comparison works)
            if (empty_i_j !== INF && tax_j_i !== INF) {
                const totalCost = empty_i_j + prices[j] + tax_j_i;
                minCost = Math.min(minCost, totalCost);
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

