fn solve(n: Int64, prices: Array[Int64], roads: Array[Array[Int64]]): Array[Int64] {
  let N = n as Int

  // Adjacency list: adj[u] = Array[Edge]
  var adj: Array[Array[Edge]] = Array.new(N) { Array.new<Edge>() }

  for road in roads {
    let u = road[0] as Int
    let v = road[1] as Int
    let cost = road[2]
    let tax = road[3]

    // Roads are bidirectional
    adj[u].push(Edge{v: v as Int64, cost: cost, tax: tax})
    adj[v].push(Edge{v: u as Int64, cost: cost, tax: tax})
  }

  const INF: Int64 = 1_000_000_000_000_000_000 // Sufficiently large number (> 10^14)

  // --- Priority Queue implementation (Min Heap) ---
  #struct PriorityQueue {
    heap: Array[Tuple[Int64, Int]] // [distance, node]

    fn new() -> PriorityQueue {
      self.heap = Array.new<Tuple[Int64, Int]>()
      self
    }

    fn empty(&self) -> Bool {
      self.heap.len == 0
    }

    fn enqueue(&mut self, element: Tuple[Int64, Int]) {
      self.heap.push(element)
      self.bubbleUp(self.heap.len - 1)
    }

    fn dequeue(&mut self) -> Maybe(Tuple[Int64, Int]) {
      if self.empty() {
        return nil
      }
      if self.heap.len == 1 {
        return Some(self.heap.pop().unwrap())
      }

      let min = self.heap[0]
      self.heap[0] = self.heap.pop().unwrap()
      self.bubbleDown(0)
      Some(min)
    }

    fn bubbleUp(&mut self, index: Int) {
      var i = index
      while i > 0 {
        let parentIndex = (i - 1) / 2
        // Compare distances (element.1)
        if self.heap[i].1 < self.heap[parentIndex].1 {
          self.heap[i], self.heap[parentIndex] = self.heap[parentIndex], self.heap[i]
          i = parentIndex
        } else {
          break
        }
      }
    }

    fn bubbleDown(&mut self, index: Int) {
      var i = index
      let lastIndex = self.heap.len - 1
      while true {
        let leftChildIndex = 2 * i + 1
        let rightChildIndex = 2 * i + 2
        var smallest = i

        // Compare distances
        if leftChildIndex <= lastIndex && self.heap[leftChildIndex].1 < self.heap[smallest].1 {
          smallest = leftChildIndex
        }

        if rightChildIndex <= lastIndex && self.heap[rightChildIndex].1 < self.heap[smallest].1 {
          smallest = rightChildIndex
        }

        if smallest != i {
          self.heap[i], self.heap[smallest] = self.heap[smallest], self.heap[i]
          i = smallest
        } else {
          break
        }
      }
    }
  }
  // --- End Priority Queue implementation ---

  /**
   * Runs Dijkstra's algorithm from a single source node.
   * @param startNode The starting node index (Int).
   * @param weightFn Function to calculate edge weight: (edge) => weight (Int64)
   * @returns Array of shortest distances from startNode to all other nodes.
   */
  fn dijkstra(startNode: Int, weightFn: (Edge) -> Int64) -> Array[Int64] {
    var dist: Array[Int64] = Array.new(N) { INF }
    dist[startNode] = 0

    var pq = PriorityQueue.new()
    // PQ stores [distance, node]
    pq.enqueue(Tuple{0, startNode})

    while let Some(Tuple{d, u}) = pq.dequeue() {
      if d > dist[u] {
        continue
      }

      for edge in adj[u] {
        let v = edge.v as Int
        let weight = weightFn(edge)

        let newDist = dist[u] + weight

        if newDist < dist[v] {
          dist[v] = newDist
          pq.enqueue(Tuple{newDist, v})
        }
      }
    }
    dist
  }

  // --- Step 1: Calculate D_empty (Shortest paths using only 'cost') ---
  // D_empty[i][j] = shortest path from i to j (empty-handed)
  var D_empty: Array[Array[Int64]] = Array.new(N) { Array.new<Int64>(N) { INF } }

  for i in 0..<N {
    // Weight function for empty travel: use edge.cost
    let emptyDistances = dijkstra(i, (edge) -> edge.cost)
    for j in 0..<N {
      D_empty[i][j] = emptyDistances[j]
    }
  }

  // --- Step 2: Calculate D_tax (Shortest paths using 'cost * tax') ---
  // D_tax[j][i] = shortest path from j to i (carrying apples)
  // Note: We run Dijkstra from j. We want D_tax[j][i], which is the distance from j to i.
  var D_tax: Array[Array[Int64]] = Array.new(N) { Array.new<Int64>(N) { INF } }

  for j in 0..<N {
    // Weight function for tax travel: use edge.cost * edge.tax
    let taxDistances = dijkstra(j, (edge) -> edge.cost * edge.tax)
    for i in 0..<N {
      D_tax[j][i] = taxDistances[i]
    }
  }

  // --- Step 3: Calculate Final Answer ANS[i] ---
  var ans: Array[Int64] = Array.new(N)

  for i in 0..<N { // i is the destination/start store
    // Option 1: Buy directly at i
    var minCost: Int64 = prices[i]

    // Option 2: Go from i to j, buy at j, return j to i
    for j in 0..<N { // j is the purchase store
      if i == j {
        continue 
      }

      // Cost = D_empty(i, j) + prices[j] + D_tax(j, i)

      let empty_i_j = D_empty[i][j]
      let tax_j_i = D_tax[j][i]

      if empty_i_j != INF && tax_j_i != INF {
        let totalCost = empty_i_j + prices[j] + tax_j_i
        if totalCost < minCost {
          minCost = totalCost
        }
      }
    }
    ans[i] = minCost
  }

  return ans
}
