struct PriorityQueue {
  heap: Array[Tuple[Int64, Int]]

  fn new() -> PriorityQueue {
    self.heap = []
    self
  }

  fn is_empty(&self) -> Bool {
    self.heap.len == 0
  }

  fn enqueue(&mut self, element: Tuple[Int64, Int]) {
    self.heap.push(element)
    self.bubble_up(self.heap.len - 1)
  }

  fn dequeue(&mut self) -> Maybe(Tuple[Int64, Int]) {
    if self.is_empty() {
      return nil
    }
    if self.heap.len == 1 {
      return self.heap.pop()
    }

    let min = self.heap[0]
    self.heap[0] = self.heap.pop()
    self.bubble_down(0)
    Some(min)
  }

  fn bubble_up(&mut self, index: Int) {
    while index > 0 {
      let parent_index = (index - 1) / 2
      // Compare distances (first element of the tuple)
      if self.heap[index].first < self.heap[parent_index].first {
        self.heap.swap(index, parent_index)
        index = parent_index
      } else {
        break
      }
    }
  }

  fn bubble_down(&mut self, index: Int) {
    let last_index = self.heap.len - 1
    loop do
      let left_child_index = 2 * index + 1
      let right_child_index = 2 * index + 2
      let mut smallest = index

      // Compare distances
      if left_child_index <= last_index && self.heap[left_child_index].first < self.heap[smallest].first {
        smallest = left_child_index
      }

      if right_child_index <= last_index && self.heap[right_child_index].first < self.heap[smallest].first {
        smallest = right_child_index
      }

      if smallest != index {
        self.heap.swap(index, smallest)
        index = smallest
      } else {
        break
      }
    end
  }
end

