fn solve(n: Int64, prices: Array[Int64], roads: Array[Array[Int64]]) -> Array[Int64] {
  // N is small enough (<= 1000) that we can use Int for indices, but prices/costs must be Int64.
  let N = n as Int

  // Adjacency list structure: adj[u] = Array[Edge]
  var adj: Array[Array[Edge]] = Array.new(N) { [] }

  for road in roads {
    // road = [u, v, cost, tax]
    let u = road[0] as Int
    let v = road[1] as Int
    let cost = road[2]
    let tax = road[3]

    // Roads are bidirectional
    adj[u].push(Edge(v: v, cost: cost, tax: tax))
    adj[v].push(Edge(v: u, cost: cost, tax: tax))
  end

  let INF: Int64 = 10^18 // Sufficiently large number for infinity

  /**
   * Runs Dijkstra's algorithm from a single source node.
   * @param startNode The starting node index (Int).
   * @param weight_fn Function to calculate edge weight: (edge) -> Int64
   * @returns Array of shortest distances from startNode to all other nodes.
   */
  fn dijkstra(startNode: Int, weight_fn: fn(Edge) -> Int64) -> Array[Int64] {
    var dist: Array[Int64] = Array.new(N) { INF }
    dist[startNode] = 0

    var pq = PriorityQueue.new()
    // PQ stores [distance, node]
    pq.enqueue(Tuple(0, startNode))

    loop do
      let item = pq.dequeue()
      if item == nil {
        break
      }
      let (d, u) = item.unwrap()

      if d > dist[u] {
        continue
      }

      for edge in adj[u] {
        let v = edge.v
        let weight = weight_fn(edge)

        let newDist = dist[u] + weight

        if newDist < dist[v] {
          dist[v] = newDist
          pq.enqueue(Tuple(newDist, v))
        }
      end
    end
    dist
  }

  // --- Step 1: Calculate D_empty (Shortest paths using only 'cost') ---
  // D_empty[i][j] = shortest path from i to j (empty-handed)
  var D_empty: Array[Array[Int64]] = Array.new(N) { [] }

  for i in 0..<N {
    // Weight function for empty travel: use edge.cost
    let emptyDistances = dijkstra(i, fn(edge) -> edge.cost)
    D_empty[i] = emptyDistances.dup
  end

  // --- Step 2: Calculate D_tax (Shortest paths using 'cost * tax') ---
  // D_tax[j][i] = shortest path from j to i (carrying apples)
  // We run Dijkstra starting at j, which gives us distances TO i.
  var D_tax: Array[Array[Int64]] = Array.new(N) { [] }

  for j in 0..<N {
